<template>
  <div class="row g-3 mt-1 m-lg-1 mb-1">
    <div>
      <div class="row m-1">
        <input
          type="text"
          class="form-control col"
          id="title"
          placeholder="عنوان"
          v-model="watch.title"
          required
        />
        <label for="title" class="col">عنوان</label>
      </div>
    </div>
    <!--    seprate-->
    <div>
      <div class="row m-1">
        <input
          type="text"
          class="form-control col"
          id="title"
          placeholder="جست و جوی سهم"
          v-model="search_term"
          @input="searchItem"
          required
        />
        <label for="title" class="col">انتخاب سهم</label>
      </div>
      <div class="row m-1 col-6">
        <div class="col" id="seachboxer">
          <button
            class="row m-1 btn btn-outline-dark"
            v-for="stock in searched_stocks"
            :key="stock.id"
            @click="select_stock(stock)"
            :id="stock.id"
          >
            {{ stock.symbol }}
          </button>
        </div>
      </div>
    </div>
    <!--    seprate-->
    <div>
      <div class="row m-1">
        <select
          class="form-select col"
          id="stock"
          required
          v-model="watch.cond_variable"
        >
          <option value="last" selected>آخرین قیمت</option>
          <option value="close">قیمت بسته شدن</option>
          <option value="open">قیمت باز شدن</option>
          <option value="yesterday">قیمت دیروز</option>
          <option value="high">بالاترین قیمت</option>
          <option value="low">پایین ترین قیمت</option>
          <option value="count">تعداد سهم</option>
          <option value="volume">حجم</option>
          <option value="value">ارزش</option>
        </select>
        <label for="title" class="col">قیمت گذاری برای</label>
      </div>
    </div>
    <!--    seprate-->
    <div>
      <div class="row m-1">
        <select
          class="form-select col"
          id="stock"
          required
          v-model="watch.cond"
        >
          <option value="gr" selected>بیشتر یا مساوی</option>
          <option value="lt">کمتر یا مساوی</option>
        </select>
        <label for="title" class="col">شرط</label>
      </div>
    </div>
    <!--    seprate-->
    <div>
      <div class="row m-1">
        <input
          type="number"
          name="Last"
          class="col form-control m-1"
          v-model="watch.condition"
          min="0"
        />
        <label for="title" class="col">مقدار</label>
      </div>
    </div>
    <!--    seprate-->
    <div class="row m-1">
      <span class="col-4"></span>
      <button
        @click="add_new_stock"
        type="button"
        class="btn btn-outline-success col-3"
      >
        اضافه کردن به واچ لیست
      </button>
    </div>
    <!--    seprate-->
  </div>
</template>

<script>
import axios from "axios";

export default {
  name: "HomeView",
  components: {},
  data() {
    return {
      watch: {
        stock: 1,
        condition: 0,
        title: "",
        cond: "gr",
        enable: true,
        cond_variable: "last",
      },
      stocks: null,
      search_term: null,
      searched_stocks: [],
    };
  },
  mounted() {
    axios.get(`${this.host}/api/stock/`).then((stk) => {
      this.stocks = stk.data;
    });
  },
  methods: {
    select_stock(stock) {
      this.watch.stock = stock.id;
      document.getElementById(stock.id).classList.add("btn-dark");
      document.getElementById(stock.id).classList.remove("btn-outline-dark");
      this.searched_stocks = [stock];
      console.log(this.watch);
    },
    searchItem() {
      if (this.stocks) {
        this.searched_stocks = [];
        for (var stock of this.stocks) {
          if (
            stock.symbol
              .substring(0, stock.symbol.length)
              .includes(this.search_term)
          ) {
            this.searched_stocks.push(stock);
            if (this.search_term.length == 0 || this.search_term === null) {
              this.searched_stocks = [];
            }
          }
        }
      }
    },
    add_new_stock() {
      if (this.watch.title.length === 0) {
        window.alert("عنوان را وارد نکرده‌اید!");
      } else {
        axios
          .post(`${this.host}/api/onwatch/`, this.watch, {
            headers: { Authorization: `Bearer ${this.getCookie("token")}` },
          })
          .then(() => {
            window.alert("به واچ لیست شما اضافه شد");
            this.$router.push("/dashboard");
          });
      }
    },
    getCookie(name) {
      const cookies = document.cookie.split(";");
      for (let i = 0; i < cookies.length; i++) {
        const cookie = cookies[i].trim(); // Remove leading/trailing spaces
        if (cookie.startsWith(name + "=")) {
          return cookie.split("=")[1]; // Extract value
        }
      }
      return null; // Cookie not found
    },
  },
};
</script>

