<template>
  <div class="row g-3 mt-1 m-lg-1 mb-1" v-if="stocks">
    <div class="col-md-4">
      <label for="title" class="form-label">Title</label>
      <input
        type="text"
        class="form-control"
        id="title"
        placeholder="Title"
        v-model="title"
        required
      />
    </div>
    <div class="col-md-4">
      <label for="stock" class="form-label">Stock</label>
      <select
        class="form-select"
        id="stock"
        required
        v-model="selectedStock"
        @change="update_prices(selectedStock)"
      >
        <option v-for="stock in stocks" :key="stock.id" :value="stock.id">
          {{ stock.longname }}
        </option>
      </select>
    </div>
    <div class="col-md-4">
      <label for="cond" class="form-label">Condition</label>
      <select class="form-select" id="cond" v-model="cond" required>
        <option selected value="lt">&lt;=</option>
        <option value="gr">&gt;=</option>
      </select>
    </div>
    <div class="row m-1">
      <div class="col m-3">
        <div class="row">
          <input
            type="number"
            name="Last"
            class="col form-control m-1"
            v-model="condition.last"
          />
          <label class="col m-3">Last</label>
          <input
            disabled
            type="text"
            name="Last"
            class="col form-control m-1"
            :value="price.last"
          />
        </div>
        <div class="row">
          <input
            type="number"
            name="Close"
            class="col form-control m-1"
            v-model="condition.close"
          />
          <label class="col m-3">Close</label>
          <input
            disabled
            type="text"
            name="Close"
            class="col form-control m-1"
            :value="price.close"
          />
        </div>
        <div class="row">
          <input
            type="number"
            name="Open"
            class="col form-control m-1"
            v-model="condition.open"
          />
          <label class="col m-3">Open</label>
          <input
            disabled
            type="text"
            name="Open"
            class="col form-control m-1"
            :value="price.open"
          />
        </div>
        <div class="row">
          <input
            type="number"
            name="Yesterday"
            class="col form-control m-1"
            v-model="condition.yesterday"
          />
          <label class="col m-3">Yesterday</label>
          <input
            disabled
            type="text"
            name="Yesterday"
            class="col form-control m-1"
            :value="price.yesterday"
          />
        </div>
        <div class="row">
          <input
            type="number"
            name="High"
            class="col form-control m-1"
            v-model="condition.high"
          />
          <label class="col m-3">High</label>
          <input
            disabled
            type="text"
            name="High"
            class="col form-control m-1"
            :value="price.high"
          />
        </div>
        <div class="row">
          <input
            type="number"
            name="Low"
            class="col form-control m-1"
            v-model="condition.low"
          />
          <label class="col m-3">Low</label>
          <input
            disabled
            type="text"
            name="Low"
            class="col form-control m-1"
            :value="price.low"
          />
        </div>
        <div class="row">
          <input
            type="number"
            name="Count"
            class="col form-control m-1"
            v-model="condition.count"
          />
          <label class="col m-3">Count</label>
          <input
            disabled
            type="text"
            name="Count"
            class="col form-control m-1"
            :value="price.count"
          />
        </div>
        <div class="row">
          <input
            type="number"
