            name="Volume"
            class="col form-control m-1"
            :value="price.volume"
          />
        </div>
        <div class="row">
          <input
            type="number"
            name="Value"
            class="col form-control m-1"
            v-model="condition.value"
          />
          <label class="col m-3">Value</label>
          <input
            disabled
            type="text"
            name="Value"
            class="col form-control m-1"
            :value="price.value"
          />
        </div>
      </div>
    </div>
    <div class="form-check form-switch">
      <input
        class="form-check-input"
        type="checkbox"
        role="switch"
        id="flexSwitchCheckChecked"
        v-model="enable"
      />
      <label class="form-check-label" for="flexSwitchCheckChecked"
        >Enable</label
      >
    </div>
    <div class="col mb-1" style="margin-bottom: 2px">
      <button class="btn btn-primary" type="submit" @click="add_new_stock">
        Add To Watch List
      </button>
    </div>
  </div>
</template>

<script>
import axios from "axios";

export default {
  name: "HomeView",
  components: {},
  data() {
    return {
      watch: null,
      stocks: null,
      condition: {
        last: 0,
        close: 0,
        open: 0,
        yesterday: 0,
        high: 0,
        low: 0,
        count: 0,
        volume: 0,
        value: 0,
        user: 1, //TODO: use real user
      },
      price: {
        last: 0,
        close: 0,
        open: 0,
        yesterday: 0,
        high: 0,
        low: 0,
        count: 0,
        volume: 0,
        value: 0,
      },
      jdata: null,
      title: null,
      cond: null,
      enable: true,
      selectedStock: null,
      user_price: null,
    };
  },
  mounted() {
    axios.get(`${this.host}/api/stock/`).then((stk) => {
      this.stocks = stk.data;
    });
  },
  methods: {
    update_prices(selectedValue) {
      axios.get(`${this.host}/api/price/${selectedValue}/`).then((prc) => {
        this.price = prc.data;
      });
    },
    add_new_stock() {
      axios
        .post(`${this.host}/api/priceuser/`, this.condition, {
          headers: { Authorization: `Bearer ${this.getCookie("token")}` },
        })
        .then((uprc) => {
          this.user_price = uprc.data;
          this.jdata = {
            title: this.title,
            cond: this.cond,
            enable: this.enable,
            user: 1, //TODO: use real user
            stock: this.selectedStock,
            condition: this.user_price.id,
          };
          axios
            .post(`${this.host}/api/onwatch/`, this.jdata, {
              headers: { Authorization: `Bearer ${this.getCookie("token")}` },
            })
            .then((onw) => {
              window.alert("add to your watch list");
              console.log(onw);
              this.$router.push("/dashboard");
            });
        });
    },
    getCookie(name) {
      const cookies = document.cookie.split(";");
      for (let i = 0; i < cookies.length; i++) {
        const cookie = cookies[i].trim(); // Remove leading/trailing spaces
        if (cookie.startsWith(name + "=")) {
          return cookie.split("=")[1]; // Extract value
        }
      }
      return null; // Cookie not found
    },
  },
};
</script>

