<template>
  <div>
    <div class="col img-router m-2">
      <div class="card" v-if="stock">
        <img src="../assets/stock.png" class="card-img-top" />
        <div class="card-body">
          <h5 class="card-title">{{ item.title }}</h5>
          <hr />
          <h5 class="card-title">سهم : {{ stock.symbol }}</h5>
          <hr />
          <h5 class="card-title">مقدار : {{ item.condition }}</h5>
          <hr />
          <p class="card-text btn btn-outline-success" v-if="item.enable">
            فعال
          </p>
          <p class="card-text btn btn-outline-danger" v-else>غیر فعال</p>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import axios from "axios";

export default {
  name: "StockCmp",
  props: {
    item: {
      type: Object,
    },
  },
  data() {
    return {
      stock: null,
    };
  },
  mounted() {
    axios
      .get(`${this.host}/api/stock/${this.item.stock}`, {
        headers: { Authorization: `Bearer ${this.getCookie("token")}` },
      })
      .then((res) => {
        this.stock = res.data;
      });
  },
  methods: {
    getCookie(name) {
      const cookies = document.cookie.split(";");
      for (let i = 0; i < cookies.length; i++) {
        const cookie = cookies[i].trim(); // Remove leading/trailing spaces
        if (cookie.startsWith(name + "=")) {
          return cookie.split("=")[1]; // Extract value
        }
      }
      return null; // Cookie not found
    },
  },
};
</script>

<style scoped>
.img-router {
  text-decoration: none;
}
</style>
